import{_ as t,c as e,o as s,a5 as l}from"./chunks/framework.C2QCpDA7.js";const v=JSON.parse('{"title":"Lesli Modular Ecosystem","description":"","frontmatter":{},"headers":[],"relativePath":"engines/lesli/about/ecosystem.md","filePath":"engines/lesli/about/ecosystem.md","lastUpdated":1723943107000}'),a={name:"engines/lesli/about/ecosystem.md"},o=l('<h1 id="lesli-modular-ecosystem" tabindex="-1">Lesli Modular Ecosystem <a class="header-anchor" href="#lesli-modular-ecosystem" aria-label="Permalink to &quot;Lesli Modular Ecosystem&quot;">​</a></h1><h2 id="collections-and-modules" tabindex="-1">Collections and Modules <a class="header-anchor" href="#collections-and-modules" aria-label="Permalink to &quot;Collections and Modules&quot;">​</a></h2><p>Lesli core is meant to work with modules (Standard RoR engines) to extend the Lesli features and create custom software as required.</p><p>There are several engines created and ready for production developed by the Lesli team, most of them are open source.</p><h3 id="collections" tabindex="-1">Collections <a class="header-anchor" href="#collections" aria-label="Permalink to &quot;Collections&quot;">​</a></h3><p>A collection is a group of modules that belongs to a category or a business industry.</p><div class="columns is-multiline lesli-css-color-collections"><div class="column"><div class="has-text-centered px-4 py-6 has-text-white bg-lesli-css-color-collection-administration"> 1. Administration </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-white bg-lesli-css-color-collection-sales"> 2. Sales &amp; Marketing </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-white bg-lesli-css-color-collection-productivity"> 3. Productivity &amp; Teamwork </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-white bg-lesli-css-color-collection-finance"> 4. Finance </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-black bg-lesli-css-color-collection-analytics"> 5. Analytics </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-white bg-lesli-css-color-collection-intelligence"> 6. Intelligence </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-black bg-lesli-css-color-collection-it"> 7. IT &amp; Help Desk </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-black bg-lesli-css-color-collection-security"> 8. Security &amp; Privacy </div></div><div class="column"><div class="has-text-centered px-4 py-6 has-text-black bg-lesli-css-color-collection-integration"> 9. Integrations </div></div></div><h3 id="module-ecosystem" tabindex="-1">Module ecosystem <a class="header-anchor" href="#module-ecosystem" aria-label="Permalink to &quot;Module ecosystem&quot;">​</a></h3><p>Currently we have planned the development of 45 modules, 11 modules are already developed and ready for production.</p><table class="table is-fullwidth is-striped" style="display:table;"><tr><td>0101.</td><td>LesliAdmin</td><td>Lesli administration area</td></tr><tr><td>0202.</td><td>LesliHouse</td><td>Real Estate Management</td></tr><tr><td>0301.</td><td>LesliCalendar</td><td>Unified Calendar App</td></tr><tr><td>0305.</td><td>LesliLetter</td><td>Notes &amp; Notebooks</td></tr><tr><td>0306.</td><td>LesliDashoard</td><td>Smart business assistant</td></tr><tr><td>0308.</td><td>LesliBell</td><td>Notification system</td></tr><tr><td>0502.</td><td>LesliAudit</td><td>System analytics</td></tr><tr><td>0702.</td><td>LesliSupport</td><td>Support Ticket System</td></tr><tr><td>0801.</td><td>LesliShield</td><td>Authentication &amp; Authorization module for the Lesli Framework.</td></tr><tr><td>0802.</td><td>LesliSecurity</td><td>Users, Privileges &amp; Access Management for the Lesli Framework.</td></tr><tr><td>0901.</td><td>LesliBabel</td><td>Translation management</td></tr></table><p><br><br></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>You can create your own modules, we&#39;ll cover that part later in this documentation.</p></div>',12),i=[o];function d(c,r,n,m,u,p){return s(),e("div",null,i)}const y=t(a,[["render",d]]);export{v as __pageData,y as default};
